import {Component, signal, computed} from '@angular/core';
import {bootstrapApplication} from '@angular/platform-browser';

@Component({
  selector: 'app-root',
  template: `
    <h2>Cookie recipe</h2>

    <label>
      # of cookies:
      <input type="range" min="10" max="100" step="10" [value]="count()" (input)="update($event)" />
      {{ count() }}
    </label>

    <p>Butter: {{ butter() }} cup(s)</p>
    <p>Sugar: {{ sugar() }} cup(s)</p>
    <p>Flour: {{ flour() }} cup(s)</p>
  `,
})
export class CookieRecipe {
  readonly count = signal(10);

  readonly butter = computed(() => this.count() * 0.1);
  readonly sugar = computed(() => this.count() * 0.05);
  readonly flour = computed(() => this.count() * 0.2);

  update(event: Event) {
    const input = event.target as HTMLInputElement;
    this.count.set(parseInt(input.value));
  }
}

bootstrapApplication(CookieRecipe);

import {Component} from '@angular/core';
import {bootstrapApplication} from '@angular/platform-browser';

@Component({
  selector: 'app-root',
  template: `
    <h2>Todos</h2>
    <input #text />
    <button (click)="add(text.value)">Add</button>

    @for (todo of todos; track $index) {
      <p>
        <input type="checkbox" (change)="toggle($index)" />
        @if (todo.done) {
          <s>{{ todo.text }}</s>
        } @else {
          <span>{{ todo.text }}</span>
        }
      </p>
    } @empty {
      <p>No todos</p>
    }
  `,
})
export class Todos {
  todos: Array<{done: boolean; text: string}> = [];

  add(text: string) {
    this.todos.push({text, done: false});
  }

  toggle(index: number) {
    this.todos[index].done = !this.todos[index].done;
  }
}

bootstrapApplication(Todos);

import React from "react";
import styled from "styled-components";
import { escapeRegExp } from "lodash";

const TextHighlighter = styled.mark`
  color: var(--ads-highlight-text-default-text-color);
  background-color: var(--ads-highlight-text-default-background-color);
`;

export type HighlightTextProps = {
  highlight: string;
  text: string;
} & React.HTMLAttributes<HTMLSpanElement>;

export function HighlightText(props: HighlightTextProps) {
  const { highlight = "", text = "", ...rest } = props;

  if (!highlight.trim()) {
    return (
      <span data-testid="t--no-highlight" {...rest}>
        {text}
      </span>
    );
  }

  const regex = new RegExp(`(${escapeRegExp(highlight)})`, "gi");
  const parts: string[] = text.split(regex);

  return (
    <span className="search-highlight" {...rest}>
      {parts.filter(String).map((part, i) => {
        return regex.test(part) ? (
          <TextHighlighter data-testid="t--highlighted-text" key={i}>
            {part}
          </TextHighlighter>
        ) : (
          <span data-testid="t--non-highlighted-text" key={i}>
            {part}
          </span>
        );
      })}
    </span>
  );
}

import React from "react";
