import { useEffect, useState } from 'react';
import { getAuthorName, loadToolsData, ProtoTool } from '../../../data/proto-tools';
import ToolCard from './ToolCard';

export interface ToolCardsProps {
	data: 'built-in' | 'third-party';
}

export default function ToolCards(props: ToolCardsProps) {
	const [tools, setTools] = useState<ProtoTool[]>([]);
	const isThirdParty = props.data === 'third-party';

	useEffect(() => {
		// eslint-disable-next-line promise/prefer-await-to-then
		loadToolsData(props.data).then(setTools).catch(console.error);
	}, []);

	return (
		<div className="grid grid-cols-2 gap-2">
			{tools.map((tool, index) => {
				const id = `${tool.id}-${isThirdParty ? getAuthorName(tool.author) : 'native'}-${index}`;

				return (
					<div key={id} id={id}>
						<ToolCard id={tool.id} tool={tool} builtin={!isThirdParty} />
					</div>
				);
			})}
		</div>
	);
}

import cx from 'clsx';
import { alignment, overflows, transforms, variants } from './Text';
import { TypographyProps } from './types';

export type HeadingLevel = 1 | 2 | 3 | 4 | 5 | 6;

export type HeadingElement = 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6' | 'p';

export interface HeadingProps extends Omit<TypographyProps, 'weight'> {
	as?: HeadingElement;
	className?: string;
	level: HeadingLevel;
}

const levels: Record<HeadingLevel, string> = {
	1: 'text-4xl font-extrabold sm:text-5xl',
	2: 'text-3xl font-bold sm:text-4xl',
	3: 'text-2xl font-bold',
	4: 'text-xl font-bold',
	5: 'text-lg font-semibold',
	6: 'text-base font-semibold',
};

export default function Heading({
	align,
	as,
	children,
	className = '',
	level,
	overflow = 'wrap',
	transform,
	variant = 'neutral',
}: HeadingProps) {
	const Tag = (as ?? `h${level}`) as 'h1';

	return (
		<Tag
			className={cx(
				'm-0',
				align && alignment[align],
				levels[level],
				overflows[overflow],
				transform && transforms[transform],
				variants[variant],
				className,
			)}
		>
			{children}
		</Tag>
	);
}

import { useTheme } from '@mui/material/styles';
import { useFocusedItem } from '../hooks';
import { useSankeyLayout } from '../hooks/useSankeySeries';

export function FocusedSankeyNode(props: React.SVGAttributes<SVGRectElement>) {
  const focusedItem = useFocusedItem();
  const layout = useSankeyLayout();
  const theme = useTheme();

  if (!focusedItem || focusedItem.type !== 'sankey' || focusedItem.subType !== 'node' || !layout) {
    return null;
  }
  const node = layout?.nodes.find(({ id }) => id === focusedItem.nodeId);

  if (!node) {
    return null;
  }

  const x0 = node.x0 ?? 0;
  const y0 = node.y0 ?? 0;
  const x1 = node.x1 ?? 0;
  const y1 = node.y1 ?? 0;

  return (
    <rect
      x={x0}
      y={y0}
      width={x1 - x0}
      height={y1 - y0}
      fill="none"
      stroke={(theme.vars ?? theme).palette.text.primary}
      strokeWidth={2}
      pointerEvents="none"
      {...props}
    />
  );
}

