export function msToString(ms: number): string {
  if (ms < 0 || !isFinite(ms))
    return '-';

  if (ms === 0)
    return '0ms';

  if (ms < 1000)
    return ms.toFixed(0) + 'ms';

  const seconds = ms / 1000;
  if (seconds < 60)
    return seconds.toFixed(1) + 's';

  const minutes = seconds / 60;
  if (minutes < 60)
    return minutes.toFixed(1) + 'm';

  const hours = minutes / 60;
  if (hours < 24)
    return hours.toFixed(1) + 'h';

  const days = hours / 24;
  return days.toFixed(1) + 'd';
}

export function bytesToString(bytes: number): string {
  if (bytes < 0 || !isFinite(bytes))
    return '-';

  if (bytes === 0)
    return '0';

  if (bytes < 1000)
    return bytes.toFixed(0);

  const kb = bytes / 1024;
  if (kb < 1000)
    return kb.toFixed(1) + 'K';

  const mb = kb / 1024;
  if (mb < 1000)
    return mb.toFixed(1) + 'M';

  const gb = mb / 1024;
  return gb.toFixed(1) + 'G';
}

export class LRUCache<K, V> {
  private _maxSize: number;
  private _map: Map<K, { value: V, size: number }>;
  private _size: number;

  constructor(maxSize: number) {
    this._maxSize = maxSize;
    this._map = new Map();
    this._size = 0;
  }

  getOrCompute(key: K, compute: () => { value: V, size: number }): V {
    if (this._map.has(key)) {
      const result = this._map.get(key)!;
      // reinserting makes this the least recently used entry
      this._map.delete(key);
      this._map.set(key, result);
      return result.value;
    }

    const result = compute();

    while (this._map.size && this._size + result.size > this._maxSize) {
      const [firstKey, firstValue] = this._map.entries().next().value!;
      this._size -= firstValue.size;
      this._map.delete(firstKey);
    }

    this._map.set(key, result);
    this._size += result.size;
    return result.value;
  }
}

import { ComponentType, Runtime } from '../config';

export function buildComponentName(fqn: string, type: ComponentType, entrypoint: string) {
  const id = fqn.split('/').at(-1)?.replace('-provider', '') ?? '';
  const handler = entrypoint.split('.').at(-1)?.replace(/[_Hh]andler/g, '') ?? '';
  const name = (id.replace(
    /-([a-z])/g, (s) => { return s[1].toUpperCase(); },
  )) + (handler.charAt(0).toUpperCase() + handler.slice(1));
  return name.charAt(0).toUpperCase()
    + name.slice(1)
    + (type === ComponentType.CUSTOM_RESOURCE_PROVIDER ? 'Provider' : type);
}

export function toLambdaRuntime(runtime: Runtime) {
  switch (runtime) {
    case Runtime.NODEJS_20_X: {
      return 'lambda.Runtime.NODEJS_20_X';
    }
    case Runtime.PYTHON_3_9: {
      return 'lambda.Runtime.PYTHON_3_9';
    }
    case Runtime.PYTHON_3_10: {
      return 'lambda.Runtime.PYTHON_3_10';
    }
    case Runtime.PYTHON_3_11: {
      return 'lambda.Runtime.PYTHON_3_11';
    }
    case Runtime.PYTHON_3_13: {
      return 'lambda.Runtime.PYTHON_3_13';
    }
  }
}

import type { SeriesId } from '../../../../../models/seriesType/common';
import type { ChartSeriesType } from '../../../../../models/seriesType/config';
import type { ProcessedSeries } from '../../../corePlugins/useChartSeries/useChartSeries.types';

export function getNonEmptySeriesArray<OutSeriesType extends Exclude<ChartSeriesType, 'sankey'>>(
  series: ProcessedSeries<ChartSeriesType>,
  availableSeriesTypes: Set<OutSeriesType>,
): { seriesId: SeriesId; type: OutSeriesType }[] {
  return Object.keys(series)
    .filter((type): type is OutSeriesType => availableSeriesTypes.has(type as OutSeriesType))
    .flatMap((type) => {
      const seriesOfType = series[type]!;
      return seriesOfType.seriesOrder
        .filter((seriesId: SeriesId) => {
          const seriesItem = seriesOfType.series[seriesId];
          if ('hidden' in seriesItem && seriesItem.hidden) {
            return false;
          }
          return (
            seriesItem.data.length > 0 && seriesItem.data.some((value: unknown) => value != null)
          );
        })
        .map((seriesId: SeriesId) => ({
          type,
          seriesId,
        }));
    });
}

import { existsSync, mkdirSync } from 'node:fs';
import { join } from 'node:path';
import type { I18nOptions } from '../models';

export function ensureOutputPaths(
  baseOutputPath: string,
  i18n: I18nOptions
): Map<string, string> {
  const outputPaths = getLocaleOutputPaths(i18n);

  for (const [, outputPath] of outputPaths) {
    const fullPath = join(baseOutputPath, outputPath);
    if (!existsSync(fullPath)) {
      mkdirSync(fullPath, { recursive: true });
    }
  }

  return outputPaths;
}

export function getLocaleOutputPaths(i18n: I18nOptions): Map<string, string> {
  const outputPaths: [string, string][] = i18n.shouldInline
    ? [...i18n.inlineLocales].map((l) => [
        l,
        i18n.flatOutput ? '' : i18n.locales[l].subPath,
      ])
    : [['', '']];

  return new Map(outputPaths);
}

import type { HTMLConverter } from '../types.js'

import { convertLexicalNodesToHTML } from '../serializeLexical.js'

const ALLOWED_HEADING_TAGS = new Set(['h1', 'h2', 'h3', 'h4', 'h5', 'h6'])
const ALLOWED_TEXT_ALIGN = new Set(['center', 'end', 'justify', 'left', 'right', 'start'])

export const HeadingHTMLConverter: HTMLConverter<any> = {
  async converter({ converters, node, parent, submissionData }) {
    const childrenText = await convertLexicalNodesToHTML({
      converters,
      lexicalNodes: node.children,
      parent: {
        ...node,
        parent,
      },
      submissionData,
    })
    const tag = ALLOWED_HEADING_TAGS.has(node?.tag) ? node.tag : 'h1'
    const style = [
      node.format && ALLOWED_TEXT_ALIGN.has(node.format) ? `text-align: ${node.format};` : '',
      node.indent > 0 ? `padding-inline-start: ${node.indent * 40}px;` : '',
    ]
      .filter(Boolean)
      .join(' ')
    return `<${tag}${style ? ` style='${style}'` : ''}>${childrenText}</${tag}>`
  },
  nodeTypes: ['heading'],
}

'use client'
export class Point {
  private readonly _x: number

  private readonly _y: number

  constructor(x: number, y: number) {
    this._x = x
    this._y = y
  }

  public calcDeltaXTo({ x }: Point): number {
    return this.x - x
  }

  public calcDeltaYTo({ y }: Point): number {
    return this.y - y
  }

  public calcDistanceTo(point: Point): number {
    return Math.sqrt(Math.pow(this.calcDeltaXTo(point), 2) + Math.pow(this.calcDeltaYTo(point), 2))
  }

  public calcHorizontalDistanceTo(point: Point): number {
    return Math.abs(this.calcDeltaXTo(point))
  }

  public calcVerticalDistance(point: Point): number {
    return Math.abs(this.calcDeltaYTo(point))
  }

  public equals({ x, y }: Point): boolean {
    return this.x === x && this.y === y
  }

  get x(): number {
    return this._x
  }

  get y(): number {
    return this._y
  }
}

export function isPoint(x: unknown): x is Point {
  return x instanceof Point
}

