import { useState } from 'react';

export function getInputOnChange<T>(
  setValue: (value: null | undefined | T | ((current: T) => T)) => void
) {
  return (val: null | undefined | T | React.ChangeEvent<any> | ((current: T) => T)) => {
    if (!val) {
      setValue(val as T);
    } else if (typeof val === 'function') {
      setValue(val);
    } else if (typeof val === 'object' && 'nativeEvent' in val) {
      const { currentTarget } = val;

      if (currentTarget.type === 'checkbox') {
        setValue((currentTarget as any).checked as any);
      } else {
        setValue(currentTarget.value as any);
      }
    } else {
      setValue(val);
    }
  };
}

export type UseInputStateReturnValue<T> = [
  T,
  (value: null | undefined | T | React.ChangeEvent<any>) => void,
];

export function useInputState<T>(initialState: T): UseInputStateReturnValue<T> {
  const [value, setValue] = useState<T>(initialState);
  return [value, getInputOnChange<T>(setValue as any)];
}

export namespace useInputState {
  export type ReturnValue<T> = UseInputStateReturnValue<T>;
}

export function lazy<TRouter extends AnyRouter>(
  importRouter: () => Promise<
    | TRouter
    | {
        [key: string]: TRouter;
      }
  >,
): Lazy<NoInfer<TRouter>> {
  async function resolve(): Promise<TRouter> {
    const mod = await importRouter();

    // if the module is a router, return it
    if (isRouter(mod)) {
      return mod;
    }

    const routers = Object.values(mod);

    if (routers.length !== 1 || !isRouter(routers[0])) {
      throw new Error(
        "Invalid router module - either define exactly 1 export or return the router directly.\nExample: `lazy(() => import('./slow.js').then((m) => m.slowRouter))`",
      );
    }

    return routers[0];
  }

  (resolve as Lazy<NoInfer<TRouter>>)[lazyMarker] = true as const;

  return resolve as Lazy<NoInfer<TRouter>>;
}

import kebabCase from "lodash/kebabCase";
import isObject from "lodash/isObject";
import type { Theme } from "../theme";
import { objectKeys } from "@appsmith/utils";
import type { TypographyVariantMetric } from "../token";

export const cssRule = (tokens: Theme) => {
  let styles = "";

  objectKeys(tokens).forEach((tokenKey) => {
    const token = tokens[tokenKey];

    if (token == null) return;

    if (isObject(token)) {
      if (tokenKey === "typography") {
        styles += objectKeys(token as NonNullable<Theme["typography"]>).reduce(
          (prev: string, key) => {
            return `${prev} --font-size-${key}: ${(token[key] as TypographyVariantMetric).fontSize};`;
          },
          "",
        );

        return;
      }

      objectKeys(token).forEach((key) => {
        //@ts-expect-error: type mismatch
        styles += `--${kebabCase(token[key].type)}-${kebabCase(key)}: ${
          //@ts-expect-error: type mismatch
          token[key].value
        };`;
      });
    }
  });

  return styles;
};

import { tailwindLayers } from "constants/Layers";
import React from "react";
import styled from "styled-components";
import useResize, {
  DIRECTION,
  type CallbackResponseType,
} from "utils/hooks/useResize";

const ResizeHandler = styled.div`
  &:hover {
    background-color: var(--ads-v2-color-border);
  }
`;

export const EntityExplorerResizeHandler = ({
  resizeRef,
  storedHeightKey,
}: {
  resizeRef: React.RefObject<HTMLDivElement>;
  storedHeightKey: string;
}) => {
  const resizeAfterCallback = (data: CallbackResponseType) => {
    localStorage.setItem(storedHeightKey, data.height.toString());
  };

  const { mouseDown, setMouseDown } = useResize(
    resizeRef,
    DIRECTION.vertical,
    resizeAfterCallback,
  );

  return (
    <div
      className={`absolute -bottom-2 left-0 w-full h-2 group cursor-ns-resize ${tailwindLayers.resizer}`}
      onMouseDown={() => setMouseDown(true)}
    >
      <ResizeHandler
        className={`w-full h-1 bg-transparent hover:bg-transparent transform transition
          ${mouseDown ? "" : ""}
          `}
      />
    </div>
  );
};
